#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
╔══════════════════════════════════════════════════════════════╗
║   ATUALIZADOR DO DASHBOARD — Manutenção Fibra MultCaixa           ║
║   Coloque este script na mesma pasta da planilha .xlsx       ║
║   Clique duas vezes para atualizar o dashboard               ║
╚══════════════════════════════════════════════════════════════╝

Requisitos: pip install pandas openpyxl
"""

import os, sys, json, re, gzip, base64, glob, subprocess, platform
from datetime import datetime
from pathlib import Path

# ── Template do dashboard (comprimido) ──
TEMPLATE_B64 = """"""

# ─────────────────────────────────────────
#  FUNÇÕES AUXILIARES
# ─────────────────────────────────────────

def find_xlsx():
    """Encontra a planilha .xlsx mais recente na pasta do script."""
    folder = Path(__file__).parent
    files = sorted(folder.glob("*.xlsx"), key=lambda f: f.stat().st_mtime, reverse=True)
    # Ignorar arquivos temporários do Excel (~$...)
    files = [f for f in files if not f.name.startswith("~$")]
    return files[0] if files else None

def parse_xlsx(path):
    """Lê a planilha e retorna lista de máquinas com registros."""
    try:
        import pandas as pd
    except ImportError:
        print("\n❌  Pandas não encontrado. Instale com: pip install pandas openpyxl")
        input("\nPressione Enter para sair...")
        sys.exit(1)

    xl = pd.read_excel(path, sheet_name=None)

    # Mapear operadores pelo nome da aba
    def extract_operator(name):
        for sep in [" – ", " - "]:
            if sep in name:
                part = name.split(sep)[-1].strip()
                if not re.match(r"^\d+$", part):
                    return part
        return "N/D"

    def split_parts(raw):
        if not raw or str(raw).upper() == "OK" or str(raw).strip() == "":
            return []
        return [p.strip() for p in re.split(r",|;| e | E ", str(raw))
                if p.strip() and p.strip().upper() != "OK" and len(p.strip()) > 1]

    machines = []
    for name, df in xl.items():
        operator = extract_operator(name)
        all_rows = [df.columns.tolist()] + df.values.tolist()
        header_idx = next(
            (i for i, r in enumerate(all_rows) if any("DATA" in str(c).upper() for c in r)), -1
        )
        if header_idx == -1:
            continue

        records = []
        for row in all_rows[header_idx + 1:]:
            raw = row[0]
            if not raw or str(raw).strip() in ("", "nan", "NaT"):
                continue
            # Formatar data
            if hasattr(raw, "strftime"):
                date = raw.strftime("%d/%m/%Y")
            else:
                date = str(raw).split(" ")[0].split("T")[0]

            def clean(v):
                s = str(v).strip() if v is not None else ""
                return "" if s in ("nan", "NaT", "None") else s

            problem   = clean(row[1] if len(row) > 1 else "")
            parts_raw = clean(row[2] if len(row) > 2 else "")
            time_raw  = clean(row[3] if len(row) > 3 else "")
            try:
                time_min = int(float(time_raw)) if time_raw.upper() not in ("OK", "") else 0
            except:
                time_min = 0

            is_ok     = problem.upper() == "OK" or problem == ""
            parts_arr = split_parts(parts_raw)

            records.append({
                "date":     date,
                "problem":  problem,
                "partsRaw": parts_raw,
                "partsArr": parts_arr,
                "timeMin":  time_min,
                "isOk":     is_ok,
                "operator": operator,
            })

        machines.append({"name": name, "operator": operator, "records": records})

    return machines

def build_html(machines, xlsx_name):
    """Reconstrói o HTML injetando os dados atualizados."""
    template_bytes = gzip.decompress(base64.b64decode(TEMPLATE_B64))
    template = template_bytes.decode("utf-8")

    data_js = "const DEFAULT_DATA = " + json.dumps(machines, ensure_ascii=False)
    html = template.replace("###DEFAULT_DATA###", data_js)

    # Atualizar comentário de data
    now = datetime.now().strftime("%d/%m/%Y %H:%M")
    html = html.replace(
        "// ── DADOS PADRÃO (Fichário Técnico · Caixas · Fev 2026) ──",
        f"// ── DADOS: {xlsx_name} · Atualizado em {now} ──"
    )
    return html

def open_browser(path):
    """Abre o HTML no navegador padrão."""
    url = path.as_uri()
    system = platform.system()
    try:
        if system == "Windows":
            os.startfile(str(path))
        elif system == "Darwin":
            subprocess.run(["open", str(path)])
        else:
            subprocess.run(["xdg-open", str(path)])
    except:
        print(f"\n🌐  Abra manualmente: {url}")

# ─────────────────────────────────────────
#  MAIN
# ─────────────────────────────────────────

def main():
    print("=" * 60)
    print("  ATUALIZADOR DASHBOARD — Manutenção Fibra MultCaixa")
    print("=" * 60)

    # 1. Encontrar planilha
    xlsx = find_xlsx()
    if not xlsx:
        print("\n❌  Nenhuma planilha .xlsx encontrada nesta pasta.")
        input("\nPressione Enter para sair...")
        sys.exit(1)

    print(f"\n📂  Planilha encontrada: {xlsx.name}")
    print("    Lendo dados...")

    # 2. Parsear
    try:
        machines = parse_xlsx(xlsx)
    except Exception as e:
        print(f"\n❌  Erro ao ler planilha: {e}")
        input("\nPressione Enter para sair...")
        sys.exit(1)

    total_records = sum(len(m["records"]) for m in machines)
    total_fails   = sum(sum(1 for r in m["records"] if not r["isOk"]) for m in machines)
    print(f"    ✅  {len(machines)} máquinas · {total_records} registros · {total_fails} ocorrências")

    # 3. Gerar HTML
    out_path = Path(__file__).parent / "dashboard_manutencao.html"
    print(f"\n⚙️   Gerando dashboard...")
    html = build_html(machines, xlsx.name)

    with open(out_path, "w", encoding="utf-8") as f:
        f.write(html)

    size_kb = out_path.stat().st_size // 1024
    print(f"    ✅  Salvo: {out_path.name}  ({size_kb} KB)")

    # 4. Copiar para index.html
    index_path = Path(__file__).parent / "index.html"
    import shutil
    shutil.copy2(out_path, index_path)

    # 5. Publicar no GitHub
    print(f"\n📤  Publicando no GitHub...")
    pasta = str(Path(__file__).parent)
    try:
        subprocess.run(['git', 'add', 'dashboard_manutencao.html', 'index.html'], cwd=pasta, check=True)
        subprocess.run(['git', 'commit', '-m', f'Atualiza dashboard - {datetime.now().strftime("%d/%m/%Y %H:%M")}'], cwd=pasta, check=True)
        subprocess.run(['git', 'push'], cwd=pasta, check=True)
        print("    ✅  GitHub atualizado!")
        print(f"    🌐  https://fabryciomsn-ops.github.io/dashboard-manutencao/")
    except subprocess.CalledProcessError:
        print("    ⚠️   Erro ao publicar no GitHub (verifique o token)")

    # 6. Abrir no navegador
    print(f"\n🌐  Abrindo no navegador...")
    open_browser(out_path)

    print("\n✅  Concluído!")
    print("=" * 60)
    input("\nPressione Enter para fechar...")

if __name__ == "__main__":
    main()
